import React, { useState } from 'react';
import { Mail, Lock, User, Ruler, Palette, ChevronRight, ChevronLeft, Sparkles, Shirt } from 'lucide-react';
import './styles/AuthPage.css';

const AuthPage = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '', email: '', password: '', gender: '',
    height: '', weight: '', skinTone: '',
    chest: '', waist: '', hips: ''
  });

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const nextStep = () => setStep(step + 1);
  const prevStep = () => setStep(step - 1);

  return (
    <div className="auth-fluid-wrapper">
      {/* Background Decorative Elements */}
      <div className="auth-ambient-glow"></div>

      <div className="auth-split-layout">
        
        {/* Left Side: Immersive Brand Experience */}
        <div className="auth-brand-side">
          <div className="brand-sticky-content">
            <div className="auth-logo-premium">
              <Sparkles className="sparkle-icon" size={32} />
              <span>StyleMirror</span>
            </div>
            <h1 className="brand-statement">
              {isLogin ? "Welcome back to the " : "Define your "}
              <span className="text-gradient">Digital Silhouette.</span>
            </h1>
            <p className="brand-subtext">
              Securely access your Neural-Fit™ profile and explore clothes that actually fit your reality.
            </p>
            <div className="brand-visual-hint">
              <div className="hint-line"></div>
              <span>SECURE JWT ENCRYPTION ACTIVE</span>
            </div>
          </div>
        </div>

        {/* Right Side: Floating Form (No Card) */}
        <div className="auth-form-side">
          <div className="form-inner-container">
            <header className="form-nav">
              <button 
                className={isLogin ? "nav-active" : ""} 
                onClick={() => {setIsLogin(true); setStep(1);}}
              >
                Sign In
              </button>
              <button 
                className={!isLogin ? "nav-active" : ""} 
                onClick={() => {setIsLogin(false); setStep(1);}}
              >
                Register
              </button>
            </header>

            <form className="fluid-form" onSubmit={(e) => e.preventDefault()}>
              {isLogin ? (
                <div className="form-step-animate">
                  <div className="input-field">
                    <label>Email Address</label>
                    <div className="input-box">
                      <Mail size={18} />
                      <input type="email" placeholder="name@company.com" />
                    </div>
                  </div>
                  <div className="input-field">
                    <label>Password</label>
                    <div className="input-box">
                      <Lock size={18} />
                      <input type="password" placeholder="••••••••" />
                    </div>
                  </div>
                  <div className="form-aux">
                    <label className="checkbox-container">
                      <input type="checkbox" /> <span className="checkmark"></span> Remember me
                    </label>
                    <span className="forgot-link">Forgot Password?</span>
                  </div>
                </div>
              ) : (
                <div className="form-step-animate">
                  {step === 1 ? (
                    <div className="step-content">
                      <div className="input-field">
                        <label>Full Name</label>
                        <div className="input-box"><User size={18} /><input type="text" placeholder="John Doe" /></div>
                      </div>
                      <div className="input-field">
                        <label>Email</label>
                        <div className="input-box"><Mail size={18} /><input type="email" placeholder="john@example.com" /></div>
                      </div>
                      <div className="input-field">
                        <label>Create Password</label>
                        <div className="input-box"><Lock size={18} /><input type="password" placeholder="Min. 8 characters" /></div>
                      </div>
                    </div>
                  ) : (
                    <div className="step-content grid-inputs">
                      <div className="input-field"><label>Height (cm)</label><div className="input-box"><Ruler size={18} /><input type="number" /></div></div>
                      <div className="input-field"><label>Weight (kg)</label><div className="input-box"><User size={18} /><input type="number" /></div></div>
                      <div className="input-field"><label>Skin Tone</label><div className="input-box"><Palette size={18} /><input type="text" /></div></div>
                      <div className="input-field"><label>Chest (cm)</label><div className="input-box"><Shirt size={18} /><input type="number" /></div></div>
                    </div>
                  )}
                </div>
              )}

              <div className="form-footer-actions">
                {!isLogin && step === 1 ? (
                  <button type="button" className="btn-fluid-primary" onClick={nextStep}>
                    Next Step <ChevronRight size={18} />
                  </button>
                ) : (
                  <div className="btn-combo">
                    {!isLogin && <button type="button" className="btn-fluid-outline" onClick={prevStep}><ChevronLeft size={20} /></button>}
                    <button type="submit" className="btn-fluid-primary">
                      {isLogin ? "Authenticate" : "Finalize Profile"}
                    </button>
                  </div>
                )}
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
